from page_objects import AppPage

from playwright.sync_api import expect

def test_Product_data_base_check_shown_data_base_table(page):


    #Start on any page like
    page.goto("http://10.40.226.200/BC_Team_2/index.php")

    app=AppPage.AppPage(page)

    #Check if "Admin" link in the right upper corner redirects to product data web page and if all objects on the page are existing

    page.locator("#accountbar > a").click()
    app.login("MarkusTE", "Mark0426TE") 
    expect(page.locator("#loginContainer")).to_be_visible() 
    

    # öffne Artikelpflege-Page  
    #page.locator('//*[@id="shoppingcart"]').click()
    page.goto("http://10.40.226.200/BC_Team_2/artikeldatenpflege.php")




    # zeige die Tabellenelemente auf der Seite zum Pflegen der Artikeldaten
    
    expect(page.locator("h2")).to_contain_text("Artikeldatenpflege")
    expect(page.locator("#td_productname1")).to_contain_text("Nivea Creme")
    expect(page.locator("#td_preis1")).to_contain_text("1.99")
    expect(page.locator("#td_bestand1")).to_contain_text("6")
    expect(page.locator("#td_beschreibung1")).to_contain_text("")

    #die "" sind im Originalsource Code leer
    expect(page.locator("#td_blob1")).to_contain_text("")        

    #zwischen den "" müsste noch das folgende Bild eingefügt werden: <img src="data:image/png;base64," height="50">

    expect(page.locator("#td_product_editButton1")).to_contain_text("img src=img/edit.png")

    #1. es soll das Edit-Image angezeigt werden
    #2. es soll der folgende JS-Befehl ausgeführt werden: <a href="javascript:toggleProductsEdit('1')" title="Datensatz 1 editieren"><img src="img/edit.png" style="width:15px;height:15px; alt=" datensatz="" editieren"=""></a>
    

    expect(page.locator("#td_product_deleteButton1")).to_contain_text("img src=img/no.png")
  
    #1. es soll das no-Image angezeigt werden
    #2. es soll der folgende JS-Befehl ausgeführt werden: <a href="javascript:deleteData('products','1')" title="Datensatz 1 löschen"><img src="img/no.png" style="width:15px;height:15px; alt=" datensatz="" löschen"=""></a>
